{
  "sentences": [
    {
      "text": "你應該早點睡覺。",
      "pinyin": "Nǐ yīnggāi zǎo diǎn shuìjiào.",
      "pinyin_numeric": "ni3 ying1gai1 zao3 dian3 shui4jiao4",
      "translation_en": "You should go to bed earlier.",
      "translation_ko": "너는 좀 더 일찍 자야 해."
    },
    {
      "text": "我們必須遵守規定。",
      "pinyin": "Wǒmen bìxū zūnshǒu guīdìng.",
      "pinyin_numeric": "wo3men bi4xu1 zun1shou3 gui1ding4",
      "translation_en": "We must follow the rules.",
      "translation_ko": "우리는 규칙을 지켜야 합니다."
    },
    {
      "text": "你不需要買那麼多東西。",
      "pinyin": "Nǐ bù xūyào mǎi nàme duō dōngxī.",
      "pinyin_numeric": "ni3 bu4 xu1yao4 mai3 na4me duo1 dong1xi1",
      "translation_en": "You don't need to buy so many things.",
      "translation_ko": "너는 그렇게 많은 물건을 살 필요가 없어."
    },
    {
      "text": "我建議你試試看這個。",
      "pinyin": "Wǒ jiànyì nǐ shì shì kàn zhège.",
      "pinyin_numeric": "wo3 jian4yi4 ni3 shi4 shi4 kan4 zhe4ge5",
      "translation_en": "I suggest you try this.",
      "translation_ko": "이걸 한번 시도해 보는 게 좋겠어요."
    },
    {
      "text": "你最好帶一把雨傘。",
      "pinyin": "Nǐ zuì hǎo dài yī bǎ yǔsǎn.",
      "pinyin_numeric": "ni3 zui4 hao3 dai4 yi1 ba3 yu3san3",
      "translation_en": "You had better bring an umbrella.",
      "translation_ko": "우산을 가져가는 게 좋을 거예요."
    },
    {
      "text": "你不應該在這裡抽煙。",
      "pinyin": "Nǐ bù yīnggāi zài zhèlǐ chōuyān.",
      "pinyin_numeric": "ni3 bu4 ying1gai1 zai4 zhe4li3 chou1yan1",
      "translation_en": "You shouldn't smoke here.",
      "translation_ko": "여기서 담배를 피우면 안 돼요."
    },
    {
      "text": "我們得趕快決定。",
      "pinyin": "Wǒmen děi gǎnkuài juédìng.",
      "pinyin_numeric": "wo3men dei3 gan3kuai4 jue2ding4",
      "translation_en": "We have to decide quickly.",
      "translation_ko": "우리는 빨리 결정해야 해요."
    },
    {
      "text": "你必須對自己的行為負責。",
      "pinyin": "Nǐ bìxū duì zìjǐ de xíngwéi fùzé.",
      "pinyin_numeric": "ni3 bi4xu1 dui4 zi4ji3 de5 xing2wei2 fu4ze2",
      "translation_en": "You must take responsibility for your actions.",
      "translation_ko": "너는 자신의 행동에 책임을 져야 해."
    },
    {
      "text": "為了健康，你應該多運動。",
      "pinyin": "Wèile jiànkāng, nǐ yīnggāi duō yùndòng.",
      "pinyin_numeric": "wei4le5 jian4kang1 ni3 ying1gai1 duo1 yun4dong4",
      "translation_en": "For your health, you should exercise more.",
      "translation_ko": "건강을 위해 운동을 더 해야 해요."
    },
    {
      "text": "你不必擔心，一切都會沒問題。",
      "pinyin": "Nǐ bùbì dānxīn, yīqiè dōu huì méi wèntí.",
      "pinyin_numeric": "ni3 bu4bi4 dan1xin1 yi1qie4 dou1 hui4 mei2 wen4ti2",
      "translation_en": "You don't have to worry; everything will be fine.",
      "translation_ko": "걱정할 필요 없어요. 모든 게 괜찮을 거예요."
    }
  ]
}
